#include <algorithm>
using namespace std;

long long solve(long long n, long long m, long long k) {
    auto cover_1d = [k](long long len) {
        if (len == 0) return 0LL;
        long long covered = -1;
        long long cnt = 0;
        while (covered < len - 1) {
            long long center = min(covered + 1 + k, len - 1);
            covered = center + k;
            cnt++;
        }
        return cnt;
    };
    return cover_1d(n) * cover_1d(m);
}
```

